// ===== 购物场景配置 =====
interface Scenario {
  id: string;
  icon: string;
  title: string;
  question: string;
  answer: number; // 正确答案（数值）
}

const SCENARIOS: Scenario[] = [
  {
    id: "stationery",
    icon: "✏️",
    title: "买文具",
    question: "一支铅笔 0.5 元，一块橡皮 0.8 元，一共多少元？",
    answer: 1.3,
  },
  {
    id: "fruit",
    icon: "🍎",
    title: "称水果",
    question: "苹果 2.5 元一斤，买了 2 斤，一共多少元？",
    answer: 5,
  },
  {
    id: "change",
    icon: "💰",
    title: "找零钱",
    question: "买了一个 3.6 元的本子，付了 5 元，找零多少元？",
    answer: 1.4,
  },
];

// 答案校验：parseFloat 让 "5" 与 "5.0" 等效
const checkAnswer = (input: string, target: number): boolean => {
  const n = parseFloat(input);
  if (Number.isNaN(n)) return false;
  return Math.abs(n - target) < 0.001;
};

type Phase = "answer" | "done";

