export default function ApplyPage() {
  const [scenarioIdx, setScenarioIdx] = useState(0);
  const scenario = SCENARIOS[scenarioIdx];
  const [phase, setPhase] = useState<Phase>("answer");
  const [answer, setAnswer] = useState("");
  const [encourage, setEncourage] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  const [doneSet, setDoneSet] = useState<Set<string>>(new Set());

  const inputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = () => {
    if (!answer.trim()) return;
    if (checkAnswer(answer, scenario.answer)) {
      setPhase("done");
      setCompleteMsg(getRandomComplete());
      setEncourage("");
      setDoneSet((prev) => new Set(prev).add(scenario.id));
    } else {
      // 答错：抖动 + 鼓励语，不使用红色提示
      triggerShake(inputRef.current);
      setEncourage(getRandomEncourage());
      setAnswer("");
      setTimeout(() => inputRef.current?.focus(), 120);
    }
  };

  const switchScenario = (idx: number) => {
    if (idx === scenarioIdx) return;
    setScenarioIdx(idx);
    setAnswer("");
    setEncourage("");
    setPhase(doneSet.has(SCENARIOS[idx].id) ? "done" : "answer");
  };

  const retry = () => {
    setDoneSet((prev) => {
      const next = new Set(prev);
      next.delete(scenario.id);
      return next;
    });
    setPhase("answer");
    setAnswer("");
    setEncourage("");
    setTimeout(() => inputRef.current?.focus(), 100);
  };

  const nextStep = getNextStep("decimal", "apply");
  const allDone = SCENARIOS.every((s) => doneSet.has(s.id));

  const renderIllustration = () => {
    switch (scenario.id) {
      case "stationery":
        return <StationerySVG />;
      case "fruit":
        return <ScaleSVG />;
      case "change":
        return <WalletSVG />;
      default:
        return null;
    }
  };

  const renderResult = () => {
    if (scenario.id === "stationery") {
      return (
        <div className="flex flex-wrap items-center justify-center gap-3 sm:gap-5">
          <div className="flex flex-col items-center">
            <span className="text-4xl">✏️</span>
            <span className="mt-1 text-xs text-[var(--text-secondary)]">
              铅笔 0.5 元
            </span>
          </div>
          <span className="text-2xl font-bold text-[var(--text-muted)]">+</span>
          <div className="flex flex-col items-center">
            <span className="text-4xl">🧽</span>
            <span className="mt-1 text-xs text-[var(--text-secondary)]">
              橡皮 0.8 元
            </span>
          </div>
          <span className="text-2xl font-bold text-[var(--text-muted)]">=</span>
          <div className="flex flex-col items-center rounded-xl bg-[var(--bg-soft)] px-4 py-2">
            <span className="text-4xl">💰</span>
            <span className="mt-1 text-lg font-bold text-[var(--primary)]">
              1.3 元
            </span>
          </div>
        </div>
      );
    }
    if (scenario.id === "fruit") {
      return (
        <div className="flex flex-wrap items-center justify-center gap-3 sm:gap-5">
          <div className="flex flex-col items-center">
            <div className="flex gap-1 text-4xl">
              <span>🍎</span>
              <span>🍎</span>
            </div>
            <span className="mt-1 text-xs text-[var(--text-secondary)]">
              2.5 元/斤 × 2 斤
            </span>
          </div>
          <span className="text-2xl font-bold text-[var(--text-muted)]">=</span>
          <div className="flex flex-col items-center rounded-xl bg-[var(--bg-soft)] px-4 py-2">
            <span className="text-4xl">💰</span>
            <span className="mt-1 text-lg font-bold text-[var(--primary)]">
              5.0 元
            </span>
          </div>
        </div>
      );
    }
    // change：找零动画
    return (
      <div className="flex flex-wrap items-center justify-center gap-3 sm:gap-5">
        <div className="flex flex-col items-center">
          <span className="text-4xl">💵</span>
          <span className="mt-1 text-xs text-[var(--text-secondary)]">
            付 5 元
          </span>
        </div>
        <span className="text-2xl font-bold text-[var(--text-muted)]">−</span>
        <div className="flex flex-col items-center">
          <span className="text-4xl">📓</span>
          <span className="mt-1 text-xs text-[var(--text-secondary)]">
            本子 3.6 元
          </span>
        </div>
        <span className="text-2xl font-bold text-[var(--text-muted)]">=</span>
        <div className="flex flex-col items-center rounded-xl bg-[var(--bg-soft)] px-4 py-2">
          <div className="flex gap-1">
            <span className="inline-block text-3xl animate-bounce-soft">🪙</span>
            <span
              className="inline-block text-3xl animate-bounce-soft"
              style={{ animationDelay: "0.25s" }}
            >
              🪙
            </span>
            <span
              className="inline-block text-3xl animate-bounce-soft"
              style={{ animationDelay: "0.5s" }}
            >
              🪙
            </span>
          </div>
          <span className="mt-1 text-lg font-bold text-[var(--primary)]">
            找零 1.4 元
          </span>
        </div>
      </div>
    );
  };

  return (
    <StepShell topicId="decimal" stepId="apply">
      <div className="space-y-6">
        {/* 场景选择 */}
        <div className="flex flex-wrap justify-center gap-3">
          {SCENARIOS.map((s, i) => (
            <button
              key={s.id}
              onClick={() => switchScenario(i)}
              className={`rounded-full px-5 py-2 text-sm font-medium transition-all ${
                i === scenarioIdx
                  ? "bg-[var(--signal-focus)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                  : "bg-[var(--bg-soft)] text-[var(--text-secondary)] hover:bg-[var(--signal-focus)]/30"
              }`}
            >
              {s.icon} {s.title}
              {doneSet.has(s.id) && (
                <span className="ml-1 text-[var(--signal-success)]">✓</span>
              )}
            </button>
          ))}
        </div>

        {/* 场景卡片 */}
        <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <div className="flex items-start gap-4">
            <div className="text-4xl">{scenario.icon}</div>
            <div className="flex-1">
              <h2 className="text-lg font-semibold text-[var(--text)]">
                {scenario.title}
              </h2>
              <p className="mt-1 text-[var(--text-secondary)]">
                {scenario.question}
              </p>
            </div>
          </div>
          <div className="mt-4">{renderIllustration()}</div>
        </section>

        {/* 答题阶段 */}
        {phase === "answer" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <p className="text-center text-sm font-medium text-[var(--text)]">
              算一算，把答案填进去
            </p>
            {encourage && (
              <p className="mt-2 text-center text-sm text-[var(--signal-shake)]">
                {encourage}
              </p>
            )}
            <div className="mt-5 flex flex-wrap items-center justify-center gap-3">
              <input
                ref={inputRef}
                type="text"
                inputMode="decimal"
                value={answer}
                onChange={(e) =>
                  setAnswer(e.target.value.replace(/[^0-9.]/g, ""))
                }
                onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
                className="w-32 rounded-xl border-2 border-[var(--border)] px-4 py-2.5 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                placeholder="?"
                autoFocus
              />
              <span className="text-[var(--text-secondary)]">元</span>
              <button
                onClick={handleSubmit}
                className="rounded-full bg-[var(--signal-confirmed)] px-6 py-2.5 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                确定
              </button>
            </div>
            <p className="mt-3 text-center text-xs text-[var(--text-muted)]">
              提示：可以写成 5 或 5.0，都算对哦
            </p>
          </section>
        )}

        {/* 完成阶段 */}
        {phase === "done" && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
            <div className="text-5xl animate-bounce-soft">{scenario.icon}</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <div className="mt-4">{renderResult()}</div>
            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={retry}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再做一次
              </button>
              {SCENARIOS.filter((s) => !doneSet.has(s.id)).map((s) => (
                <button
                  key={s.id}
                  onClick={() => switchScenario(SCENARIOS.indexOf(s))}
                  className="rounded-full bg-[var(--accent)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
                >
                  试试{s.title} →
                </button>
              ))}
            </div>
          </section>
        )}

        {/* 三个场景全部完成 */}
        {allDone && (
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-soft)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-4xl">🎉</div>
            <h2 className="mt-2 text-xl font-bold text-[var(--text)]">
              三个购物场景全部完成！
            </h2>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              你已经会用小数算价钱、称水果、找零钱啦
            </p>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="mt-5 inline-block rounded-full bg-[var(--signal-confirmed)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:-translate-y-0.5"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </section>
        )}
      </div>
    </StepShell>
  );
}
